  private boolean isSameGroup(ModifiedNode.Kind prevNodeKind, ModifiedNode.Kind nodeKind, ModifiedNode node, ModifiedNode prevNode) {

    if (prevNodeKind == null) {
      return true;
    }
    if (nodeKind != prevNodeKind) {
      return false;
    }
    if (nodeKind == ModifiedNode.Kind.PRESENCE) {
      return true;
    }

    ModifiedNode oppositeNode = node.getOppositeNode();
    ModifiedNode prevOppositeNode = prevNode.getOppositeNode();
    if (!(Objects.equals(prevOppositeNode.getParentId(), oppositeNode.getParentId())) || !(Objects.equals(prevOppositeNode.getLink(), oppositeNode.getLink()))) {
      return false;
    }

    List<SNodeId> oppositeIds = getLinkChildrenIds(oppositeNode.getParentId(), oppositeNode.getLink(), oppositeNode.isNew());
    int prevIndex = ListSequence.fromList(oppositeIds).indexOf(prevOppositeNode.getNodeId());
    int index = ListSequence.fromList(oppositeIds).indexOf(oppositeNode.getNodeId());
    return index == prevIndex + 1;
  }

