  private Set<ModelChange> collectIdChangeChildren(SNodeId oldParentId, SNodeId newParentId) {

    final ModifiedNode oldParentNode = MapSequence.fromMap(myOldModifiedNodes).get(oldParentId);
    final ModifiedNode newParentNode = MapSequence.fromMap(myNewModifiedNodes).get(newParentId);

    Iterable<SContainmentLink> links = ListSequence.fromList(oldParentNode.getChildren()).select(new ISelector<ModifiedNode, SContainmentLink>() {
      public SContainmentLink select(ModifiedNode it) {
        return it.getLink();
      }
    }).distinct().concat(ListSequence.fromList(newParentNode.getChildren()).select(new ISelector<ModifiedNode, SContainmentLink>() {
      public SContainmentLink select(ModifiedNode it) {
        return it.getLink();
      }
    }).distinct()).distinct();

    final Set<ModelChange> result = SetSequence.fromSet(new HashSet<ModelChange>());
    Sequence.fromIterable(links).visitAll(new IVisitor<SContainmentLink>() {
      public void visit(SContainmentLink link) {
        SetSequence.fromSet(result).addSequence(SetSequence.fromSet(collectGroupedChangesForLink(oldParentNode.getNode(), newParentNode.getNode(), link)));
      }
    });
    return result;
  }

  private List<Pair<SNodeId, SNodeId>> createIdChangesMap(List<SNodeId> oldIds, List<SNodeId> newIds) {
    List<Pair<SNodeId, SNodeId>> newToOldPairs = ListSequence.fromList(new ArrayList<Pair<SNodeId, SNodeId>>());
    int prevIdChangeNewIndex = -1;
    for (SNodeId oldNodeId : oldIds) {
      for (int i = prevIdChangeNewIndex + 1; i < ListSequence.fromList(newIds).count(); i++) {
        SNodeId newNodeId = ListSequence.fromList(newIds).getElement(i);
        SNode oldNode = myChangeSet.getOldModel().getNode(oldNodeId);
        SNode newNode = myChangeSet.getNewModel().getNode(newNodeId);
        if (!(Objects.equals(SNodeOperations.getConcept(oldNode), SNodeOperations.getConcept(newNode)))) {
          continue;
        }
        if (!(SNodeCompare.conceptHasStaticScopeNone(SNodeOperations.getConcept(oldNode), myChangeSet.getOldModel()))) {
          continue;
        }
        if (DiffUtil.allPropertiesAreEqual(oldNode, newNode) && DiffUtil.allReferencesAreEqual(oldNode, newNode)) {
          ListSequence.fromList(newToOldPairs).addElement(new Pair(newNodeId, oldNodeId));
          prevIdChangeNewIndex = i;
          break;
        }
      }
    }
    return newToOldPairs;
  }
